import{_ as e,o as i,c as o,a2 as s}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Buenas practicas","description":"","frontmatter":{},"headers":[],"relativePath":"bases-de-datos/snowflake/09-buenas-practicas.md","filePath":"bases-de-datos/snowflake/09-buenas-practicas.md","lastUpdated":1782521464000}'),r={name:"bases-de-datos/snowflake/09-buenas-practicas.md"};function l(c,a,n,t,d,u){return i(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="buenas-practicas" tabindex="-1">Buenas practicas <a class="header-anchor" href="#buenas-practicas" aria-label="Permalink to &quot;Buenas practicas&quot;">​</a></h1><p>Snowflake es facil de empezar a usar, pero tambien facil de encarecer o desordenar si no hay gobierno desde el principio.</p><h2 id="organizacion" tabindex="-1">Organizacion <a class="header-anchor" href="#organizacion" aria-label="Permalink to &quot;Organizacion&quot;">​</a></h2><p>Recomendaciones:</p><ul><li>Databases por entorno o dominio.</li><li>Schemas por capas: <code>raw</code>, <code>staging</code>, <code>marts</code>, <code>sandbox</code>.</li><li>Warehouses por tipo de carga.</li><li>Roles por responsabilidad.</li><li>Convenciones de nombres documentadas.</li></ul><h2 id="datos" tabindex="-1">Datos <a class="header-anchor" href="#datos" aria-label="Permalink to &quot;Datos&quot;">​</a></h2><ul><li>Guarda datos crudos antes de transformar.</li><li>Usa tipos explicitos en capas limpias.</li><li>Evita <code>VARIANT</code> en modelos finales salvo necesidad.</li><li>Documenta tablas finales.</li><li>Usa Time Travel y clones como herramientas de recuperacion y prueba.</li></ul><h2 id="seguridad" tabindex="-1">Seguridad <a class="header-anchor" href="#seguridad" aria-label="Permalink to &quot;Seguridad&quot;">​</a></h2><ul><li>No trabajes con <code>ACCOUNTADMIN</code> a diario.</li><li>Concede permisos a roles.</li><li>Usa minimo privilegio.</li><li>Protege PII con masking y row access cuando aplique.</li><li>Audita accesos y permisos.</li></ul><h2 id="costes" tabindex="-1">Costes <a class="header-anchor" href="#costes" aria-label="Permalink to &quot;Costes&quot;">​</a></h2><ul><li>Activa <code>AUTO_SUSPEND</code>.</li><li>Empieza con warehouses pequenos.</li><li>Separa cargas pesadas.</li><li>Revisa query history.</li><li>Limpia clones, tablas temporales y stages abandonados.</li><li>Etiqueta o clasifica cargas por equipo si necesitas chargeback.</li></ul><h2 id="operacion" tabindex="-1">Operacion <a class="header-anchor" href="#operacion" aria-label="Permalink to &quot;Operacion&quot;">​</a></h2><ul><li>Monitoriza pipelines y cargas.</li><li>Revisa errores de <code>COPY</code>.</li><li>Documenta runbooks.</li><li>Prueba restauraciones o recuperaciones.</li><li>Controla cambios de permisos.</li></ul><h2 id="checklist-inicial" tabindex="-1">Checklist inicial <a class="header-anchor" href="#checklist-inicial" aria-label="Permalink to &quot;Checklist inicial&quot;">​</a></h2><ul><li>Roles basicos creados.</li><li>Warehouses con auto suspend.</li><li>Schemas por capas.</li><li>Cargas entrando en raw.</li><li>Future grants definidos.</li><li>Query history revisado periodicamente.</li><li>Datos sensibles identificados.</li></ul><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><ul><li>Usar un unico warehouse para todo.</li><li>Mezclar raw y marts.</li><li>Dar permisos directos a usuarios.</li><li>No revisar costes hasta fin de mes.</li><li>Crear clones temporales y olvidarlos.</li><li>Tratar Snowflake como si fuera una base local tradicional.</li></ul>',17)])])}const m=e(r,[["render",l]]);export{h as __pageData,m as default};
